from unittest.mock import Mock, patch, MagicMock
import pytest

def fetch_data(url):
    import requests
    resp = requests.get(url)
    resp.raise_for_status()
    return resp.json()

class TestFetchData:
    @patch('requests.get')
    def test_success(self, mock_get):
        mock_get.return_value = MagicMock(
            status_code=200,
            json=lambda: {'key': 'value'},
            raise_for_status=lambda: None,
        )
        result = fetch_data('http://example.com')
        assert result == {'key': 'value'}

    @patch('requests.get')
    def test_failure(self, mock_get):
        from requests.exceptions import HTTPError
        mock_get.return_value.raise_for_status.side_effect = HTTPError()
        with pytest.raises(HTTPError):
            fetch_data('http://example.com')

    @patch('requests.get')
    def test_side_effect(self, mock_get):
        mock_get.side_effect = [
            MagicMock(status_code=200, json=lambda: {'a': 1}, raise_for_status=lambda: None),
            ConnectionError('timeout'),
        ]
        assert fetch_data('http://example.com') == {'a': 1}
        with pytest.raises(ConnectionError):
            fetch_data('http://example.com')

from hypothesis import given, strategies as st

@given(st.lists(st.integers()))
def test_sort_invariants(arr):
    result = sorted(arr)
    assert len(result) == len(arr)              # same length
    assert all(result[i] <= result[i+1] for i in range(len(result)-1))  # sorted
    assert sorted(arr) == sorted(result)        # permutation check

@given(st.dictionaries(st.text(), st.integers()))
def test_dict_roundtrip(d):
    import json
    assert json.loads(json.dumps(d)) == d

@given(st.floats(allow_nan=False, allow_infinity=False))
def test_sqrt_inverse(x):
    import math
    assert abs(math.sqrt(x**2) - abs(x)) < 1e-10
